class Solution:
    def distributeCoins(self, root):
        # Independent approach: repeatedly compute each subtree's coin total and
        # size, summing |coins - size| over every non-root node (each such value
        # is the net flow on that node's parent edge).
        nodes = []
        def collect(node):
            if node is None:
                return
            nodes.append(node)
            collect(node.left)
            collect(node.right)
        collect(root)
        def coins(node):
            if node is None:
                return 0
            return node.val + coins(node.left) + coins(node.right)
        def size(node):
            if node is None:
                return 0
            return 1 + size(node.left) + size(node.right)
        total = 0
        for node in nodes:
            if node is root:
                continue
            total += abs(coins(node) - size(node))
        return total

