class Solution:
    def distributeCoins(self, root):
        self.moves = 0
        def dfs(node):
            if node is None:
                return 0
            left = dfs(node.left)
            right = dfs(node.right)
            self.moves += abs(left) + abs(right)
            return node.val - 1 + left + right
        dfs(root)
        return self.moves

